using namespace std;
int main() {
    int n, q;
    cin >> n >> q;
    vector<int> arr(n);
    for(int i = 0; i < n; i++) cin >> arr[i];
    while(q--) {
        int x;
        cin >> x;
        int idx = lower_bound(arr.begin(), arr.end(), x) - arr.begin();
        if(idx < n && arr[idx] == x) cout << idx << endl;
        else cout << -1 << endl;
    }
    return 0;
}

